#include <stdio.h>
#include <stdlib.h>

int main()
{
 int n,x,m,i,y;
 scanf("%d",&n);
 for(i=1;i<=n;i++){
        scanf("%d",&m);
    x=m%10;
    if(m/1111!=0) y=4;
    else if(m/111!=0) y=3;
    else if(m/11!=0) y=2;
    else y=1;
    printf("%d\n",10*(x-1)+y*(y+1)/2);
 }
    return 0;
}

